/**
 * @linm/notification — invisible lifecycle parcel.
 *
 * Owns exclusively:
 *  - SignalR connection start / stop
 *  - Push notification (FCM/VAPID) registration / deregistration
 *
 * Other MFEs must NOT call signalRService.start() or initPushNotifications().
 * They signal auth state changes via CustomEvent:
 *
 *   Login:  new CustomEvent('linm:auth:token-changed', { detail: { token: '<jwt>' } })
 *   Logout: new CustomEvent('linm:auth:token-changed', { detail: { token: null } })
 */
import React from 'react';
import { createRoot } from 'react-dom/client';
import { Provider } from 'react-redux';
import singleSpaReact from 'single-spa-react';
import { signalRService, getAuthToken, AUTH_ACCESS_TOKEN_KEY } from '@linm-soft/common-components';
import { initPushNotifications, deregisterPushNotifications } from './services/push';
import { appSettings } from './config/appSettings';
import { NotificationLifecycleBridge } from './lifecycle/NotificationLifecycleBridge';
import { notificationStore } from './store/store';
import type { IRootProps } from './types/IRootProps';

// Module-level ref so unmount can detach the listener registered in mount
let _tokenChangeHandler: ((e: Event) => void) | null = null;
let _storageHandler: ((e: StorageEvent) => void) | null = null;

// eslint-disable-next-line @typescript-eslint/no-explicit-any
const NotificationLifecycle: React.ComponentType<any> = () => (
  <Provider store={notificationStore}>
    <NotificationLifecycleBridge />
  </Provider>
);

const lifecycles = singleSpaReact({
  React,
  ReactDOMClient: { createRoot },
  rootComponent: NotificationLifecycle,
  renderType: 'createRoot',
  errorBoundary(error) { throw error; },
});

export const bootstrap = lifecycles.bootstrap;

export const mount = async (props: IRootProps) => {
  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  await lifecycles.mount(props as any);

  // Start SignalR immediately if the user is already authenticated (page refresh / returning user)
  if (appSettings.enableSignalR) {
    const token = getAuthToken();
    if (token) {
      signalRService.start().catch((err) =>
        console.warn('[Notification] Initial SignalR start failed:', err),
      );
    }
  }

  // Push notifications (browser permission is requested by the first MFE that mounts)
  if (appSettings.pushProvider !== 'none') {
    initPushNotifications().catch((err: unknown) =>
      console.warn('[Notification] Push init failed:', err),
    );
  }

  // React to same-tab login / logout dispatched by each MFE's authSlice
  _tokenChangeHandler = (e: Event) => {
    const { token } = (e as CustomEvent<{ token: string | null }>).detail;
    if (token && appSettings.enableSignalR) {
      signalRService.start().catch((err) =>
        console.warn('[Notification] SignalR start on login failed:', err),
      );
      if (appSettings.pushProvider !== 'none') initPushNotifications().catch(() => {});
    } else if (!token) {
      if (appSettings.pushProvider !== 'none') deregisterPushNotifications().catch(() => {});
      signalRService.stop().catch(() => {});
    }
  };
  window.addEventListener('linm:auth:token-changed', _tokenChangeHandler);

  // Push delegation — other MFEs dispatch these events instead of calling push directly
  window.addEventListener('linm:push:request-registration', () => {
    initPushNotifications().catch(() => {});
  });
  window.addEventListener('linm:push:request-deregister', () => {
    deregisterPushNotifications().catch(() => {});
  });

  // Cross-tab login / logout (storage event fires in other tabs only — relay as CustomEvent)
  _storageHandler = (e: StorageEvent) => {
    if (e.key !== AUTH_ACCESS_TOKEN_KEY) return;
    window.dispatchEvent(
      new CustomEvent('linm:auth:token-changed', { detail: { token: getAuthToken() } }),
    );
  };
  window.addEventListener('storage', _storageHandler);
};

export const unmount = async (props: IRootProps) => {
  if (_tokenChangeHandler) {
    window.removeEventListener('linm:auth:token-changed', _tokenChangeHandler);
    _tokenChangeHandler = null;
  }
  if (_storageHandler) {
    window.removeEventListener('storage', _storageHandler);
    _storageHandler = null;
  }
  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  await lifecycles.unmount(props as any);
  signalRService.stop().catch(() => {});
};

// ── Parcel exports (embedded in Topbar by each MFE) ──────────────────────────
export { NotificationCenterParcel } from './parcels/NotificationCenterParcel';
export { SilentModeParcel }         from './parcels/SilentModeParcel';
