import React from 'react';
import { createRoot } from 'react-dom/client';
import singleSpaReact from 'single-spa-react';
import { NotificationCenter, type NotificationCenterProps } from '@linm-soft/common-components';
import { NotificationParcelShell } from '../components/NotificationParcelShell';

const NotificationCenterWithProvider: React.FC<NotificationCenterProps> = (props) => (
  <NotificationParcelShell>
    <NotificationCenter {...props} />
  </NotificationParcelShell>
);

export const NotificationCenterParcel = singleSpaReact({
  React,
  ReactDOMClient: { createRoot },
  rootComponent: NotificationCenterWithProvider,
  renderType: 'createRoot',
  errorBoundary(error) { throw error; },
});
